// // This module scales a 24-bit input to a 4-bit output by shifting right by 20 bits and masking with 0x0F. However, it outputs the lower 4 bits of the input instead of the upper 4 bits.
module DAC_24bit (  
    input [23:0] data_in,  
    input valid,  
    output reg [3:0] data_out  
);  

always @(*) begin  
    if (valid)  
        data_out = (data_in >> 20) & 4'b1111;  
    else  
        data_out = 4'b0000;  
end  
endmodule
